import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";
const STAGES = ['Booked', 'Collected', 'Received', 'Booking In', 'All Assets Booked', 'Processing/Pricing', 'Complete'];
function App() {
  const [model, setModel] = React.useState(appsmith.model);
  const [loading, setLoading] = React.useState(false);
  React.useEffect(() => {
    appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
      setLoading(false);
    });
  }, []);
  const current = model.current_status;
  const currentIndex = STAGES.indexOf(current);
  const next = currentIndex >= 0 && currentIndex < STAGES.length - 1 ? STAGES[currentIndex + 1] : null;
  const progress = currentIndex >= 0 ? Math.round(((currentIndex + 1) / STAGES.length) * 100) : 0;
  React.useEffect(() => {
    if (next !== model.next_status) {
      appsmith.updateModel({ next_status: next });
    }
  }, [next]);
  const advance = () => {
    if (!next) return;
    setLoading(true);
    appsmith.triggerEvent('onAdvanceStatus');
  };
  return (
    <div style={{ fontFamily: 'sans-serif', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px' }}>
      <div style={{ position: 'relative', width: '140px', height: '140px' }}>
        <svg width="140" height="140" viewBox="0 0 140 140">
          <circle cx="70" cy="70" r="60" fill="none" stroke="#e5e7eb" strokeWidth="10" />
          <circle
            cx="70" cy="70" r="60" fill="none"
            stroke="#085041" strokeWidth="10"
            strokeDasharray={`${(progress / 100) * 377} 377`}
            strokeLinecap="round"
            transform="rotate(-90 70 70)"
          />
        </svg>
        <div style={{
          position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
          display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
        }}>
          <div style={{ fontSize: '22px', fontWeight: 600, color: '#111827' }}>{progress}%</div>
          <div style={{ fontSize: '11px', color: '#6b7280' }}>complete</div>
        </div>
      </div>
      <div style={{ width: '100%', display: 'flex', flexDirection: 'column', gap: '6px' }}>
        {STAGES.map((stage, i) => {
          const isDone = i < currentIndex;
          const isCurrent = i === currentIndex;
          return (
            <div key={stage} style={{
              display: 'flex', alignItems: 'center', gap: '10px',
              padding: '8px 12px', borderRadius: '6px',
              background: isCurrent ? '#E1F5EE' : (isDone ? '#f9fafb' : 'transparent'),
              border: isCurrent ? '0.5px solid #085041' : '0.5px solid transparent'
            }}>
              <div style={{
                width: '20px', height: '20px', borderRadius: '50%',
                background: isDone ? '#085041' : (isCurrent ? '#fff' : '#e5e7eb'),
                border: isCurrent ? '2px solid #085041' : 'none',
                display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0
              }}>
                {isDone && <i className="ti ti-check" style={{ fontSize: '12px', color: '#fff' }}></i>}
              </div>
              <span style={{
                fontSize: '13px',
                fontWeight: isCurrent ? 600 : 400,
                color: isDone || isCurrent ? '#111827' : '#9ca3af'
              }}>{stage}</span>
            </div>
          );
        })}
      </div>
      {next && (
        <button
          onClick={advance}
          disabled={loading}
          style={{
            width: '100%', padding: '10px', borderRadius: '6px', border: 'none',
            background: '#085041', color: '#fff', fontSize: '13px', fontWeight: 500,
            cursor: loading ? 'default' : 'pointer', opacity: loading ? 0.6 : 1
          }}
        >
    {loading ? 'Updating...' : (next === 'Booking In' ? 'Click below to start booking' : `Mark as "${next}"`)}
        </button>
      )}
      {!next && current === 'Complete' && (
        <div style={{ fontSize: '13px', color: '#6b7280', textAlign: 'center' }}>
          Collection complete
        </div>
      )}
    </div>
  );
}
appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
